function parseCSVLine(line) {
  const cells = [];
  let cur = '', inQuote = false;
  for (let i = 0; i < line.length; i++) {
    const ch = line[i];
    if (ch === '"') {
      if (inQuote && line[i+1] === '"') { cur += '"'; i++; }
      else inQuote = !inQuote;
    } else if (ch === ',' && !inQuote) {
      cells.push(cur); cur = '';
    } else {
      cur += ch;
    }
  }
  cells.push(cur);
  return cells.map(c => c.trim());
}

const lines = input.trim().split('\n').filter(Boolean);
const rows = lines.map(parseCSVLine);
const colCount = Math.max(...rows.map(r => r.length));
for (const r of rows) while (r.length < colCount) r.push('');
const widths = Array.from({ length: colCount }, (_, i) =>
  Math.max(1, ...rows.map(r => r[i].length))
);
function rule(left, mid, right, fill) {
  return left + widths.map(w => fill.repeat(w + 2)).join(mid) + right;
}
const top = rule('+', '+', '+', '-');
const mid = rule('+', '+', '+', '-');
const bot = rule('+', '+', '+', '-');
const fmt = row => '|' + row.map((c, i) => ' ' + c.padEnd(widths[i]) + ' ').join('|') + '|';
const [header, ...body] = rows;
const out = [top, fmt(header), mid, ...body.map(fmt), bot].join('\n');
return { output: out, outputLanguage: 'text' };
